import itertools


class Solution:
    def maxNumOfMarkedIndices(self, nums):
        n = len(nums)
        start = n if n % 2 == 0 else n - 1
        for size in range(start, -1, -2):
            for combo in itertools.combinations(range(n), size):
                vals = sorted(nums[i] for i in combo)
                half = size // 2
                ok = True
                for k in range(half):
                    if 2 * vals[k] > vals[half + k]:
                        ok = False
                        break
                if ok:
                    return size
        return 0

