class Solution:
    def maxNumOfMarkedIndices(self, nums):
        a = sorted(nums)
        n = len(a)
        i = 0
        count = 0
        for j in range(n - n // 2, n):
            if i < n // 2 and 2 * a[i] <= a[j]:
                count += 1
                i += 1
        return count * 2

