var maxNumOfMarkedIndices = function(nums) {
    const a = nums.slice().sort((x, y) => x - y);
    const n = a.length;
    let i = 0;
    let count = 0;
    for (let j = n - Math.floor(n / 2); j < n; j++) {
        if (i < Math.floor(n / 2) && 2 * a[i] <= a[j]) {
            count++;
            i++;
        }
    }
    return count * 2;
};
